metrics.construct_text:
{
  "PriceMomentumVolume": {
    "description": "Normalized 10-day price momentum multiplied by z-scored volume growth.",
    "variables": {
      "$sym": "PriceMomentumVolume"
    },
    "formulation": "\\frac{TS_MEAN($close, 10) - $close}{TS_MEAN($close, 10) + 1e-8} \\times ZSCORE($volume, 10)",
    "expression": "($close - TS_MEAN($close, 10)) / (TS_MEAN($close, 10) + 1e-8) * ZSCORE($volume, 10)"
  },
  "VolumeMomentum": {
    "description": "Z-scored 5-day volume growth multiplied by price momentum.",
    "variables": {
      "$sym": "VolumeMomentum"
    },
    "formulation": "ZSCORE(TS_PCTCHANGE($volume, 5), 10) \\times TS_MEAN($close, 10)",
    "expression": "TS_ZSCORE(TS_PCTCHANGE($volume, 5), 10) * TS_MEAN($close, 10)"
  },
  "VolumeReversal": {
    "description": "Z-scored 20-day volume change as a reversal signal.",
    "variables": {
      "$sym": "VolumeReversal"
    },
    "formulation": "ZSCORE(TS_PCTCHANGE($volume, 20), 10)",
    "expression": "TS_ZSCORE(TS_PCTCHANGE($volume, 20), 10)"
  }
}
